/** Gold medal gradient from Figma (node 953-3425, Imtiaz layer). */
const MEDAL_1_GRADIENT =
  "linear-gradient(98.32deg, rgb(205, 126, 50) 0.38%, rgb(255, 207, 118) 66.66%, rgb(205, 126, 50) 121.95%)";

/** Silver medal gradient from Figma (node 953-3455, Imtiaz layer). */
const MEDAL_2_GRADIENT =
  "linear-gradient(98.32deg, rgb(157, 157, 157) 0.38%, rgb(210, 210, 210) 66.66%, rgb(172, 172, 172) 121.95%)";

/** Bronze medal gradient from Figma (node 953-3485, Imtiaz layer). */
const MEDAL_3_GRADIENT =
  "linear-gradient(98.32deg, rgb(206, 95, 48) 0.38%, rgb(255, 170, 118) 66.66%, rgb(205, 86, 50) 121.95%)";

const MEDAL_STYLES: Record<
  number,
  { border: string; bg: string; text: string; gradient?: string }
> = {
  1: {
    border: "#de9948",
    bg: "#FFFFFF",
    text: "#ad732d",
    gradient: MEDAL_1_GRADIENT,
  },
  2: {
    border: "#9d9d9d",
    bg: "#FFFFFF",
    text: "#6c6c6c",
    gradient: MEDAL_2_GRADIENT,
  },
  3: {
    border: "#da672e",
    bg: "#FFFFFF",
    text: "#a95334",
    gradient: MEDAL_3_GRADIENT,
  },
};

/** Non-medal circle styles from Figma (node 953-3515): outer #ededed + inner ring. */
const PLACE_DEFAULT = {
  outerBg: "#ededed",
  outerBorder: "4px solid #f8f8f8",
  innerBorder: "1px solid #ffffff",
  text: "#6c6c6c",
  innerInset: "8.33%",
} as const;

function PlaceCircle({ place }: { place: number }) {
  const isMedal = place <= 3;
  const medalStyle = isMedal ? MEDAL_STYLES[place] : null;
  const background = isMedal && medalStyle!.gradient
    ? medalStyle!.gradient
    : isMedal
      ? medalStyle!.bg
      : PLACE_DEFAULT.outerBg;
  const border = isMedal ? `4px solid ${medalStyle!.border}` : PLACE_DEFAULT.outerBorder;
  const color = isMedal ? medalStyle!.text : PLACE_DEFAULT.text;
  return (
    <div
      style={{
        boxSizing: "content-box",
        width: 48,
        height: 48,
        borderRadius: "50%",
        border,
        background,
        color,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        flexShrink: 0,
      }}
    >
      {!isMedal && (
        <span
          aria-hidden
          style={{
            position: "absolute",
            inset: PLACE_DEFAULT.innerInset,
            borderRadius: "50%",
            border: PLACE_DEFAULT.innerBorder,
            background: PLACE_DEFAULT.outerBg,
            pointerEvents: "none",
          }}
        />
      )}
      {isMedal && (
        <span
          style={{
            position: "absolute",
            left: 0,
            top: 0,
            width: 48,
            height: 48,
            overflow: "hidden",
            color: medalStyle!.border,
            opacity: 0.7,
            display: "block",
          }}
        >
          <LaurelWreath />
        </span>
      )}
      <span
        style={{
          fontSize: 18,
          fontWeight: 600,
          position: "relative",
          zIndex: 1,
        }}
      >
        {place}
      </span>
    </div>
  );
}

